export interface ThemeColors {
  background: string;
  foreground: string;
  accent: string;
  sidebar: string;
  editor: string;
  terminal: string;
  statusBar: string;
}

export interface Theme {
  readonly id: string;
  readonly name: string;
  readonly colors: ThemeColors;
  readonly fontFamily: string;
  readonly fontSize: number;
}

export const DEFAULT_THEME_ID = "t3-dark";

const BUILT_IN_THEMES: ReadonlyArray<Theme> = [
  {
    id: "t3-dark",
    name: "T3 Dark",
    colors: {
      background: "#0c0c0c",
      foreground: "#f0f0f0",
      accent: "oklch(0.588 0.217 264)",
      sidebar: "#111111",
      editor: "#141414",
      terminal: "#000000",
      statusBar: "#1a1a1a",
    },
    fontFamily:
      '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-light",
    name: "T3 Light",
    colors: {
      background: "#ffffff",
      foreground: "#262626",
      accent: "oklch(0.488 0.217 264)",
      sidebar: "#f5f5f5",
      editor: "#fafafa",
      terminal: "#f0f0ef",
      statusBar: "#ebebeb",
    },
    fontFamily:
      '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    colors: {
      background: "#0d0f1a",
      foreground: "#e2e4f0",
      accent: "#6366f1",
      sidebar: "#0a0c14",
      editor: "#0f1120",
      terminal: "#080a10",
      statusBar: "#090b12",
    },
    fontFamily:
      '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
] as const;

const THEMES_BY_ID = new Map<string, Theme>(
  BUILT_IN_THEMES.map((theme) => [theme.id, theme]),
);

export function listThemes(): ReadonlyArray<Theme> {
  return BUILT_IN_THEMES;
}

export function getTheme(id: string): Theme {
  return THEMES_BY_ID.get(id) ?? (BUILT_IN_THEMES[0] as Theme);
}

/**
 * Returns true when the theme's colors are suitable for dark mode.
 * Determined by whether the background is a dark colour (rough luminance check
 * via the first hex channel of the background value).
 */
export function isThemeDark(theme: Theme): boolean {
  const bg = theme.colors.background.trim().toLowerCase();

  // Handle shorthand hex (#rgb / #rgba)
  const shortHex = /^#([0-9a-f])([0-9a-f])([0-9a-f])/.exec(bg);
  if (shortHex) {
    const r = parseInt(shortHex[1]! + shortHex[1]!, 16);
    const g = parseInt(shortHex[2]! + shortHex[2]!, 16);
    const b = parseInt(shortHex[3]! + shortHex[3]!, 16);
    return 0.299 * r + 0.587 * g + 0.114 * b < 128;
  }

  // Handle full hex (#rrggbb / #rrggbbaa)
  const fullHex = /^#([0-9a-f]{2})([0-9a-f]{2})([0-9a-f]{2})/.exec(bg);
  if (fullHex) {
    const r = parseInt(fullHex[1]!, 16);
    const g = parseInt(fullHex[2]!, 16);
    const b = parseInt(fullHex[3]!, 16);
    return 0.299 * r + 0.587 * g + 0.114 * b < 128;
  }

  // For non-hex formats (oklch, hsl, etc.) default to dark when the value
  // contains a very small lightness indicator.  For the built-in oklch accents
  // we return false (they are accent colours, not backgrounds).
  return bg.startsWith("oklch") ? false : true;
}

