import { useCallback, useSyncExternalStore } from "react";
import {
  DEFAULT_THEME_ID,
  getTheme,
  isThemeDark,
  listThemes,
  type Theme,
} from "@t3tools/shared/themes";

export type { Theme };

const STORAGE_KEY = "t3code:color-theme";

// ---------------------------------------------------------------------------
// Module-level external store (same pattern as useTheme.ts)
// ---------------------------------------------------------------------------

let listeners: Array<() => void> = [];
let lastSnapshot: Theme | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getStoredId(): string {
  return localStorage.getItem(STORAGE_KEY) ?? DEFAULT_THEME_ID;
}

function getSnapshot(): Theme {
  const theme = getTheme(getStoredId());
  if (lastSnapshot && lastSnapshot.id === theme.id) return lastSnapshot;
  lastSnapshot = theme;
  return theme;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyColorTheme(getTheme(getStoredId()), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// DOM application
// ---------------------------------------------------------------------------

function applyColorTheme(theme: Theme, suppressTransitions = false): void {
  const root = document.documentElement;

  if (suppressTransitions) {
    root.classList.add("no-transitions");
  }

  const dark = isThemeDark(theme);

  // Core semantic tokens
  root.style.setProperty("--background", theme.colors.background);
  root.style.setProperty("--foreground", theme.colors.foreground);
  root.style.setProperty("--card", theme.colors.background);
  root.style.setProperty("--card-foreground", theme.colors.foreground);
  root.style.setProperty("--popover", theme.colors.background);
  root.style.setProperty("--popover-foreground", theme.colors.foreground);
  root.style.setProperty("--primary", theme.colors.accent);
  root.style.setProperty("--ring", theme.colors.accent);
  root.style.setProperty("--primary-foreground", "#ffffff");

  // Derived ambient tokens based on dark / light mode
  if (dark) {
    root.style.setProperty("--secondary", "rgba(255,255,255,0.04)");
    root.style.setProperty("--secondary-foreground", theme.colors.foreground);
    root.style.setProperty("--muted", "rgba(255,255,255,0.04)");
    root.style.setProperty("--muted-foreground", "rgba(200,200,200,0.65)");
    root.style.setProperty("--accent", "rgba(255,255,255,0.05)");
    root.style.setProperty("--accent-foreground", theme.colors.foreground);
    root.style.setProperty("--border", "rgba(255,255,255,0.07)");
    root.style.setProperty("--input", "rgba(255,255,255,0.09)");
  } else {
    root.style.setProperty("--secondary", "rgba(0,0,0,0.04)");
    root.style.setProperty("--secondary-foreground", theme.colors.foreground);
    root.style.setProperty("--muted", "rgba(0,0,0,0.04)");
    root.style.setProperty("--muted-foreground", "rgba(64,64,64,0.75)");
    root.style.setProperty("--accent", "rgba(0,0,0,0.04)");
    root.style.setProperty("--accent-foreground", theme.colors.foreground);
    root.style.setProperty("--border", "rgba(0,0,0,0.09)");
    root.style.setProperty("--input", "rgba(0,0,0,0.11)");
  }

  // Theme-specific surface tokens (sidebar, editor, terminal, status bar)
  root.style.setProperty("--t3-sidebar-bg", theme.colors.sidebar);
  root.style.setProperty("--t3-editor-bg", theme.colors.editor);
  root.style.setProperty("--t3-terminal-bg", theme.colors.terminal);
  root.style.setProperty("--t3-status-bar-bg", theme.colors.statusBar);

  // Typography
  document.body.style.fontFamily = theme.fontFamily;
  document.body.style.fontSize = `${theme.fontSize}px`;

  // Dark-mode class and color-scheme (drives Tailwind dark: utilities)
  root.classList.toggle("dark", dark);
  root.style.colorScheme = dark ? "dark" : "light";

  if (suppressTransitions) {
    // Force reflow so no-transitions takes effect before class removal
    // oxlint-disable-next-line no-unused-expressions
    root.offsetHeight;
    requestAnimationFrame(() => {
      root.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyColorTheme(getTheme(getStoredId()));

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useColorTheme() {
  const theme = useSyncExternalStore(subscribe, getSnapshot);
  const availableThemes = listThemes();

  const setTheme = useCallback((next: Theme | string) => {
    const id = typeof next === "string" ? next : next.id;
    const resolved = getTheme(id);
    localStorage.setItem(STORAGE_KEY, resolved.id);
    applyColorTheme(resolved, true);
    emitChange();
  }, []);

  return { theme, setTheme, availableThemes } as const;
}

