    root.style.setProperty("--input", "rgba(0,0,0,0.11)");
  }

  // Theme-specific surface tokens (sidebar, editor, terminal, status bar)
  root.style.setProperty("--t3-sidebar-bg", theme.colors.sidebar);
  root.style.setProperty("--t3-editor-bg", theme.colors.editor);
  root.style.setProperty("--t3-terminal-bg", theme.colors.terminal);
  root.style.setProperty("--t3-status-bar-bg", theme.colors.statusBar);

  // Typography
  document.body.style.fontFamily = theme.fontFamily;
  document.body.style.fontSize = `${theme.fontSize}px`;

  // Dark-mode class and color-scheme (drives Tailwind dark: utilities)
  root.classList.toggle("dark", dark);
  root.style.colorScheme = dark ? "dark" : "light";

  if (suppressTransitions) {
    // Force reflow so no-transitions takes effect before class removal
    // oxlint-disable-next-line no-unused-expressions
    root.offsetHeight;
    requestAnimationFrame(() => {
      root.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyColorTheme(getTheme(getStoredId()));

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useColorTheme() {
  const theme = useSyncExternalStore(subscribe, getSnapshot);
  const availableThemes = listThemes();

  const setTheme = useCallback((next: Theme | string) => {
    const id = typeof next === "string" ? next : next.id;
    const resolved = getTheme(id);
    localStorage.setItem(STORAGE_KEY, resolved.id);
    applyColorTheme(resolved, true);
    emitChange();
  }, []);

  return { theme, setTheme, availableThemes } as const;
}

