import { useColorTheme } from "~/hooks/useColorTheme";

/**
 * A grid of colour-theme cards, each with a mini preview swatch and the
 * theme name. Selecting a card immediately applies the theme and persists the
 * choice to localStorage.
 */
export function ThemeSelector() {
  const { theme: activeTheme, setTheme, availableThemes } = useColorTheme();

  return (
    <div
      role="radiogroup"
      aria-label="Color theme"
      className="grid grid-cols-3 gap-2"
    >
      {availableThemes.map((theme) => {
        const selected = activeTheme.id === theme.id;
        return (
          <button
            key={theme.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`rounded-xl border px-3 pb-3 pt-2.5 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => setTheme(theme.id)}
          >
            {/* Mini preview */}
            <div
              className="mb-2.5 h-9 overflow-hidden rounded-md border border-border/50"
              aria-hidden="true"
              style={{ background: theme.colors.background }}
            >
              {/* Sidebar strip */}
              <div className="flex h-full">
                <div
                  className="h-full w-[28%] shrink-0"
                  style={{ background: theme.colors.sidebar }}
                />
                {/* Editor area */}
                <div className="flex h-full flex-1 flex-col">
                  {/* Status bar */}
                  <div
                    className="h-[6px] w-full shrink-0"
                    style={{ background: theme.colors.statusBar }}
                  />
                  {/* Editor body with accent dot */}
                  <div
                    className="relative flex-1"
                    style={{ background: theme.colors.editor }}
                  >
                    <div
                      className="absolute right-1.5 top-1.5 size-2 rounded-full"
                      style={{ background: theme.colors.accent }}
                    />
                  </div>
                  {/* Terminal strip */}
                  <div
                    className="h-[7px] w-full shrink-0"
                    style={{ background: theme.colors.terminal }}
                  />
                </div>
              </div>
            </div>

            {/* Name + badge */}
            <div className="flex min-w-0 items-center justify-between gap-1">
              <span className="truncate text-xs font-medium text-foreground">
                {theme.name}
              </span>
              {selected ? (
                <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  Active
                </span>
              ) : null}
            </div>
          </button>
        );
      })}
    </div>
  );
}

