1	import { useCallback, useSyncExternalStore } from "react";
2	import {
3	  DEFAULT_THEME_ID,
4	  getTheme,
5	  isThemeDark,
6	  listThemes,
7	  type Theme,
8	} from "@t3tools/shared/themes";
9	
10	export type { Theme };
11	
12	const STORAGE_KEY = "t3code:color-theme";
13	
14	// ---------------------------------------------------------------------------
15	// Module-level external store (same pattern as useTheme.ts)
16	// ---------------------------------------------------------------------------
17	
18	let listeners: Array<() => void> = [];
19	let lastSnapshot: Theme | null = null;
20	
21	function emitChange() {
22	  for (const listener of listeners) listener();
23	}
24	
25	function getStoredId(): string {
26	  const stored = localStorage.getItem(STORAGE_KEY);
27	  if (stored) return stored;
28	  // Persist the default so the color-theme key is always present in storage.
29	  // This lets useTheme.ts detect that the color-theme system is active and
30	  // yield dark-class management to this module.
31	  localStorage.setItem(STORAGE_KEY, DEFAULT_THEME_ID);
32	  return DEFAULT_THEME_ID;
33	}
34	
35	function getSnapshot(): Theme {
36	  const theme = getTheme(getStoredId());
37	  if (lastSnapshot && lastSnapshot.id === theme.id) return lastSnapshot;
38	  lastSnapshot = theme;
39	  return theme;
40	}
41	
42	function subscribe(listener: () => void): () => void {
43	  listeners.push(listener);
44	
45	  const handleStorage = (e: StorageEvent) => {
46	    if (e.key === STORAGE_KEY) {
47	      applyColorTheme(getTheme(getStoredId()), true);
48	      emitChange();
49	    }
50	  };
51	  window.addEventListener("storage", handleStorage);
52	
53	  return () => {
54	    listeners = listeners.filter((l) => l !== listener);
55	    window.removeEventListener("storage", handleStorage);
56	  };
57	}
58	
59	// ---------------------------------------------------------------------------
60	// DOM application
61	// ---------------------------------------------------------------------------
62	
63	function applyColorTheme(theme: Theme, suppressTransitions = false): void {
64	  const root = document.documentElement;
65	
66	  if (suppressTransitions) {
67	    root.classList.add("no-transitions");
68	  }
69	
70	  const dark = isThemeDark(theme);
71	
72	  // Core semantic tokens
73	  root.style.setProperty("--background", theme.colors.background);
74	  root.style.setProperty("--foreground", theme.colors.foreground);
75	  root.style.setProperty("--card", theme.colors.background);
76	  root.style.setProperty("--card-foreground", theme.colors.foreground);
77	  root.style.setProperty("--popover", theme.colors.background);
78	  root.style.setProperty("--popover-foreground", theme.colors.foreground);
79	  root.style.setProperty("--primary", theme.colors.accent);
80	  root.style.setProperty("--ring", theme.colors.accent);
81	  root.style.setProperty("--primary-foreground", "#ffffff");
82	
83	  // Derived ambient tokens based on dark / light mode
84	  if (dark) {
85	    root.style.setProperty("--secondary", "rgba(255,255,255,0.04)");
86	    root.style.setProperty("--secondary-foreground", theme.colors.foreground);
87	    root.style.setProperty("--muted", "rgba(255,255,255,0.04)");
88	    root.style.setProperty("--muted-foreground", "rgba(200,200,200,0.65)");
89	    root.style.setProperty("--accent", "rgba(255,255,255,0.05)");
90	    root.style.setProperty("--accent-foreground", theme.colors.foreground);
91	    root.style.setProperty("--border", "rgba(255,255,255,0.07)");
92	    root.style.setProperty("--input", "rgba(255,255,255,0.09)");
93	  } else {
94	    root.style.setProperty("--secondary", "rgba(0,0,0,0.04)");
95	    root.style.setProperty("--secondary-foreground", theme.colors.foreground);
96	    root.style.setProperty("--muted", "rgba(0,0,0,0.04)");
97	    root.style.setProperty("--muted-foreground", "rgba(64,64,64,0.75)");
98	    root.style.setProperty("--accent", "rgba(0,0,0,0.04)");
99	    root.style.setProperty("--accent-foreground", theme.colors.foreground);
100	    root.style.setProperty("--border", "rgba(0,0,0,0.09)");
101	    root.style.setProperty("--input", "rgba(0,0,0,0.11)");
102	  }
103	
104	  // Theme-specific surface tokens (sidebar, editor, terminal, status bar)
105	  root.style.setProperty("--t3-sidebar-bg", theme.colors.sidebar);
106	  root.style.setProperty("--t3-editor-bg", theme.colors.editor);
107	  root.style.setProperty("--t3-terminal-bg", theme.colors.terminal);
108	  root.style.setProperty("--t3-status-bar-bg", theme.colors.statusBar);
109	
110	  // Typography
111	  document.body.style.fontFamily = theme.fontFamily;
112	  document.body.style.fontSize = `${theme.fontSize}px`;
113	
114	  // Dark-mode class and color-scheme (drives Tailwind dark: utilities)
115	  root.classList.toggle("dark", dark);
116	  root.style.colorScheme = dark ? "dark" : "light";
117	
118	  if (suppressTransitions) {
119	    // Force reflow so no-transitions takes effect before class removal
120	    // oxlint-disable-next-line no-unused-expressions
121	    root.offsetHeight;
122	    requestAnimationFrame(() => {
123	      root.classList.remove("no-transitions");
124	    });
125	  }
126	}
127	
128	// Apply immediately on module load to prevent flash
129	applyColorTheme(getTheme(getStoredId()));
130	
131	// ---------------------------------------------------------------------------
132	// Hook
133	// ---------------------------------------------------------------------------
134	
135	export function useColorTheme() {
136	  const theme = useSyncExternalStore(subscribe, getSnapshot);
137	  const availableThemes = listThemes();
138	
139	  const setTheme = useCallback((next: Theme | string) => {
140	    const id = typeof next === "string" ? next : next.id;
141	    const resolved = getTheme(id);
142	    localStorage.setItem(STORAGE_KEY, resolved.id);
143	    applyColorTheme(resolved, true);
144	    emitChange();
145	  }, []);
146	
147	  return { theme, setTheme, availableThemes } as const;
148	}
